/* ===== src/common/settings.js ===== */
/* Linux.do 工具箱 — 设置模块 */
(() => {
  'use strict';

  const namespace = globalThis.LinuxDoToolkit = globalThis.LinuxDoToolkit || {};

  const DEFAULT_SETTINGS = Object.freeze({
    enablePostActions: true,
    enableBase64Decode: true,
    includeMetadata: true,
    replaceUploadUrls: true,
  });

  function hasChromeStorage() {
    return typeof chrome !== 'undefined' && Boolean(chrome.storage?.sync);
  }

  function normalizeSettings(value = {}) {
    return { ...DEFAULT_SETTINGS, ...value };
  }

  function getSettings() {
    if (!hasChromeStorage()) {
      return Promise.resolve(normalizeSettings());
    }

    return new Promise((resolve) => {
      chrome.storage.sync.get(DEFAULT_SETTINGS, (items) => {
        if (chrome.runtime?.lastError) {
          resolve(normalizeSettings());
          return;
        }
        resolve(normalizeSettings(items));
      });
    });
  }

  function saveSettings(partialSettings) {
    if (!hasChromeStorage()) {
      return Promise.resolve(normalizeSettings(partialSettings));
    }

    return new Promise((resolve, reject) => {
      chrome.storage.sync.set(partialSettings, () => {
        if (chrome.runtime?.lastError) {
          reject(new Error(chrome.runtime.lastError.message));
          return;
        }
        resolve();
      });
    });
  }

  function onSettingsChanged(callback) {
    if (!hasChromeStorage() || !chrome.storage?.onChanged) return;

    chrome.storage.onChanged.addListener((changes, areaName) => {
      if (areaName !== 'sync') return;
      const changedKeys = Object.keys(changes);
      const settingsKeys = Object.keys(DEFAULT_SETTINGS);
      if (!changedKeys.some((key) => settingsKeys.includes(key))) return;
      getSettings().then(callback).catch(() => callback(normalizeSettings()));
    });
  }

  namespace.settings = {
    DEFAULT_SETTINGS,
    getSettings,
    saveSettings,
    onSettingsChanged,
  };
})();


/* ===== src/content/markdown.js ===== */
/* Linux.do 工具箱 — Markdown 转换模块 */
(() => {
  'use strict';

  const namespace = globalThis.LinuxDoToolkit = globalThis.LinuxDoToolkit || {};

  // 检测内容是否为 HTML（而非纯 Markdown）。
  function isHtmlContent(text) {
    const trimmed = text.trim();
    if (!trimmed) return false;

    const parser = new DOMParser();
    const doc = parser.parseFromString(trimmed, 'text/html');
    const elCount = doc.body.querySelectorAll('*').length;

    if (elCount > 2) return true;

    for (const el of doc.body.querySelectorAll('*')) {
      if (el.attributes.length > 0) return true;
    }

    return /^<(?!p>|\/p>)[a-zA-Z][\s\S]*>/.test(trimmed);
  }

  function htmlTableToMarkdown(tableEl) {
    const rows = [];
    tableEl.querySelectorAll('tr').forEach((tr) => {
      const cells = Array.from(tr.querySelectorAll('td, th')).map((cell) => {
        return cell.textContent.trim().replace(/\|/g, '\\|');
      });
      rows.push(cells);
    });

    if (rows.length === 0) return '';

    const colCount = Math.max(...rows.map((row) => row.length));
    rows.forEach((row) => {
      while (row.length < colCount) row.push('');
    });

    const lines = [];
    lines.push('| ' + rows[0].join(' | ') + ' |');
    lines.push('| ' + rows[0].map(() => '---').join(' | ') + ' |');
    for (let i = 1; i < rows.length; i += 1) {
      lines.push('| ' + rows[i].join(' | ') + ' |');
    }

    return '\n' + lines.join('\n') + '\n\n';
  }

  // 轻量 HTML → Markdown 转换器，覆盖 Discourse 常见结构。
  function htmlToMarkdown(html) {
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');

    function walk(node) {
      if (node.nodeType === Node.TEXT_NODE) return node.textContent;
      if (node.nodeType !== Node.ELEMENT_NODE) return '';

      const tag = node.tagName.toLowerCase();
      const children = Array.from(node.childNodes).map(walk).join('');

      switch (tag) {
        case 'h1': return `\n# ${children.trim()}\n\n`;
        case 'h2': return `\n## ${children.trim()}\n\n`;
        case 'h3': return `\n### ${children.trim()}\n\n`;
        case 'h4': return `\n#### ${children.trim()}\n\n`;
        case 'h5': return `\n##### ${children.trim()}\n\n`;
        case 'h6': return `\n###### ${children.trim()}\n\n`;
        case 'p': return `\n${children.trim()}\n\n`;
        case 'br': return '\n';
        case 'hr': return '\n---\n\n';
        case 'strong':
        case 'b': {
          const text = children.trim();
          return text ? `**${text}**` : '';
        }
        case 'em':
        case 'i': {
          const text = children.trim();
          return text ? `*${text}*` : '';
        }
        case 'del':
        case 's': {
          const text = children.trim();
          return text ? `~~${text}~~` : '';
        }
        case 'code': {
          const text = children.trim();
          return text ? `\`${text}\`` : '';
        }
        case 'pre': {
          const codeEl = node.querySelector('code');
          const lang = codeEl?.className?.match(/lang-(\w+)/)?.[1] || '';
          const codeText = codeEl ? codeEl.textContent : node.textContent;
          return `\n\`\`\`${lang}\n${codeText.trim()}\n\`\`\`\n\n`;
        }
        case 'a': {
          const href = node.getAttribute('href') || '';
          const text = children.trim();
          if (!text) return '';
          return href && href !== text ? `[${text}](${href})` : text;
        }
        case 'img': {
          const src = node.getAttribute('src') || '';
          const alt = node.getAttribute('alt') || '';
          return src ? `![${alt}](${src})` : '';
        }
        case 'blockquote': {
          const lines = children.trim().split('\n').map((line) => `> ${line}`).join('\n');
          return `\n${lines}\n\n`;
        }
        case 'aside': {
          if (node.classList?.contains('quote')) {
            const titleEl = node.querySelector('.quote-controls, [data-username]');
            const quoteUser = node.getAttribute('data-username') || titleEl?.getAttribute('data-username') || '';
            const blockquote = node.querySelector(':scope > blockquote');
            const content = blockquote ? Array.from(blockquote.childNodes).map(walk).join('').trim() : children.trim();
            const attribution = quoteUser ? `**${quoteUser} said:**\n` : '';
            const lines = (attribution + content).split('\n').map((line) => `> ${line}`).join('\n');
            return `\n${lines}\n\n`;
          }
          return children;
        }
        case 'ul': {
          return '\n' + Array.from(node.children).map((li) => {
            return li.tagName?.toLowerCase() === 'li' ? `- ${walk(li).trim()}` : walk(li);
          }).join('\n') + '\n\n';
        }
        case 'ol': {
          return '\n' + Array.from(node.children).map((li, index) => {
            return li.tagName?.toLowerCase() === 'li' ? `${index + 1}. ${walk(li).trim()}` : walk(li);
          }).join('\n') + '\n\n';
        }
        case 'li': return children;
        case 'table': return htmlTableToMarkdown(node);
        case 'sup': return `<sup>${children}</sup>`;
        case 'sub': return `<sub>${children}</sub>`;
        case 'mark': return `==${children.trim()}==`;
        case 'span': {
          if (node.classList?.contains('mention')) return children.trim() || node.textContent.trim();
          return children;
        }
        case 'div': {
          if (node.classList?.contains('lightbox-wrapper')) {
            const img = node.querySelector('img');
            if (img) {
              const src = img.getAttribute('data-original-href') || img.getAttribute('src') || '';
              const alt = img.getAttribute('alt') || '';
              return src ? `\n![${alt}](${src})\n` : children;
            }
          }
          if (node.classList?.contains('onebox')) {
            const link = node.querySelector('a[href]');
            const title = node.querySelector('.onebox-body h3, .source a')?.textContent?.trim();
            const href = link?.getAttribute('href') || '';
            if (title && href) return `\n[${title}](${href})\n`;
          }
          return children;
        }
        case 'section':
        case 'article':
        case 'main':
        case 'nav':
        case 'header':
        case 'footer':
        case 'figure':
        case 'figcaption':
        case 'details':
        case 'summary':
        case 'dd':
        case 'dt':
        case 'dl':
        case 'abbr':
        case 'cite':
        case 'ins':
        case 'u':
          return children;
        default:
          return children;
      }
    }

    return walk(doc.body).replace(/\n{3,}/g, '\n\n').trim();
  }

  function ensureMarkdown(rawContent) {
    const trimmed = rawContent.trim();
    return isHtmlContent(trimmed) ? htmlToMarkdown(trimmed) : trimmed;
  }

  function normalizeDiscourseMd(md) {
    return md.replace(/!\[([^\]]+?)\|(\d+x\d+(?:x\d+)?(?:\|[^\]]*)?)\]\(/g, '![$1](');
  }

  namespace.markdown = {
    isHtmlContent,
    htmlToMarkdown,
    ensureMarkdown,
    normalizeDiscourseMd,
  };
})();


/* ===== src/content/discourse.js ===== */
/* Linux.do 工具箱 — Discourse 页面适配模块 */
(() => {
  'use strict';

  const namespace = globalThis.LinuxDoToolkit = globalThis.LinuxDoToolkit || {};

  function getTopicTitle() {
    return (
      document.querySelector('.fancy-title')?.textContent?.trim() ||
      document.querySelector('#topic-title h1')?.textContent?.trim() ||
      document.title.replace(/\s*[—–-]\s*Linux\.do\s*$/, '').trim() ||
      'Untitled'
    );
  }

  function getTopicUrl() {
    return window.location.origin + window.location.pathname;
  }

  function getTopicId() {
    const match = window.location.pathname.match(/\/t\/[^/]+\/(\d+)/);
    return match ? match[1] : null;
  }

  function getPostElements() {
    return document.querySelectorAll('[data-post-id].topic-post, .topic-post');
  }

  function getPostMeta(postEl) {
    const postId = postEl.getAttribute('data-post-id') || '';
    const postNumber = postEl.getAttribute('data-post-number') || '';
    const author =
      postEl.querySelector('.names .username')?.textContent?.trim() ||
      postEl.querySelector('.creator .username')?.textContent?.trim() ||
      'Unknown';
    const timeEl = postEl.querySelector('time');
    const date = timeEl?.getAttribute('datetime') || timeEl?.textContent?.trim() || '';
    return { postId, postNumber, author, date };
  }

  async function fetchRawPost(topicId, postNumber) {
    if (!topicId || !postNumber) throw new Error('缺少主题 ID 或楼层号');
    const res = await fetch(`/raw/${topicId}/${postNumber}`, { credentials: 'same-origin' });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.text();
  }

  function getPostImages(postEl) {
    const images = {};
    postEl.querySelectorAll('img[data-base62-sha1]').forEach((img) => {
      const src = img.getAttribute('src') || '';
      const sha1 = img.getAttribute('data-base62-sha1') || '';
      if (!sha1 || !src) return;

      const extMatch = src.match(/\.([a-zA-Z0-9]+)$/);
      const ext = extMatch ? extMatch[1] : 'png';
      images[`${sha1}.${ext}`] = src;
    });
    return images;
  }

  function replaceUploadUrls(rawMd, imageMap) {
    return rawMd.replace(/!\[([^\]]*)\]\(upload:\/\/([^)]+)\)/g, (match, alt, uploadFilename) => {
      if (imageMap[uploadFilename]) return `![${alt}](${imageMap[uploadFilename]})`;
      return match;
    });
  }

  namespace.discourse = {
    getTopicTitle,
    getTopicUrl,
    getTopicId,
    getPostElements,
    getPostMeta,
    fetchRawPost,
    getPostImages,
    replaceUploadUrls,
  };
})();


/* ===== src/content/output.js ===== */
/* Linux.do 工具箱 — 输出与反馈模块 */
(() => {
  'use strict';

  const namespace = globalThis.LinuxDoToolkit = globalThis.LinuxDoToolkit || {};

  function formatPostMd(meta, rawMd, title, url, options = {}) {
    if (options.includeMetadata === false) return rawMd.trim();

    const sourceUrl = url + (meta.postNumber ? '#post-' + meta.postNumber : '');
    const header = `<!-- 来源: ${sourceUrl} | 作者: ${meta.author}${meta.date ? ' | ' + meta.date : ''} -->`;
    return header + '\n\n' + rawMd.trim();
  }

  function formatTopicMd(posts, title, url, options = {}) {
    if (options.includeMetadata === false) {
      return posts.map((post) => post.raw.trim()).join('\n\n---\n\n');
    }

    const lines = [`<!-- 来源: ${url} -->`, ''];
    posts.forEach((post, index) => {
      const postNumber = post.meta.postNumber || index + 1;
      const postUrl = `${url}#post-${postNumber}`;
      lines.push(`<!-- #${postNumber} ${post.meta.author} | ${postUrl} -->`);
      lines.push('');
      lines.push(post.raw.trim());
      lines.push('');
    });
    return lines.join('\n');
  }

  function copyToClipboard(text) {
    return navigator.clipboard.writeText(text);
  }

  function downloadFile(content, filename) {
    const blob = new Blob([content], { type: 'text/markdown;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement('a');
    anchor.href = url;
    anchor.download = filename;
    document.body.appendChild(anchor);
    anchor.click();
    document.body.removeChild(anchor);
    URL.revokeObjectURL(url);
  }

  function sanitizeFilename(name) {
    return name.replace(/[<>:"/\\|?*\n\r]/g, '_').replace(/\s+/g, ' ').substring(0, 80);
  }

  function showToast(message) {
    let toast = document.getElementById('ldcopy-toast');
    if (!toast) {
      toast = document.createElement('div');
      toast.id = 'ldcopy-toast';
      document.body.appendChild(toast);
    }

    toast.textContent = message;
    toast.className = 'ldcopy-toast ldcopy-toast-show';
    setTimeout(() => { toast.className = 'ldcopy-toast'; }, 2000);
  }

  namespace.output = {
    formatPostMd,
    formatTopicMd,
    copyToClipboard,
    downloadFile,
    sanitizeFilename,
    showToast,
  };
})();


/* ===== src/content/post-export.js ===== */
/* Linux.do 工具箱 — 楼层导出流程模块 */
(() => {
  'use strict';

  const namespace = globalThis.LinuxDoToolkit = globalThis.LinuxDoToolkit || {};

  async function buildPostMarkdown(postEl, settings) {
    const { discourse, markdown, output } = namespace;
    const topicId = discourse.getTopicId();
    const meta = discourse.getPostMeta(postEl);
    const raw = await discourse.fetchRawPost(topicId, meta.postNumber);
    const normalized = markdown.normalizeDiscourseMd(raw);
    const processedRaw = settings.replaceUploadUrls === false
      ? normalized
      : discourse.replaceUploadUrls(normalized, discourse.getPostImages(postEl));
    const md = markdown.ensureMarkdown(processedRaw);

    return {
      meta,
      markdown: output.formatPostMd(
        meta,
        md,
        discourse.getTopicTitle(),
        discourse.getTopicUrl(),
        settings,
      ),
      raw: md,
    };
  }

  async function getAllPostsRaw(settings) {
    const { discourse } = namespace;
    const posts = [];

    for (const postEl of discourse.getPostElements()) {
      try {
        const result = await buildPostMarkdown(postEl, settings);
        posts.push({ meta: result.meta, raw: result.raw });
      } catch {
        // 单个帖子获取失败时跳过，避免影响整帖导出。
      }
    }

    return posts;
  }

  namespace.postExport = {
    buildPostMarkdown,
    getAllPostsRaw,
  };
})();


/* ===== src/content/buttons.js ===== */
/* Linux.do 工具箱 — 页面按钮注入模块 */
(() => {
  'use strict';

  const namespace = globalThis.LinuxDoToolkit = globalThis.LinuxDoToolkit || {};

  const COPY_ICON = '<svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor"><path d="M16 1H4c-1.1 0-2 .9-2 2v14h2V3h12V1zm3 4H8c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h11c1.1 0 2-.9 2-2V7c0-1.1-.9-2-2-2zm0 16H8V7h11v14z"/></svg>';
  const DOWNLOAD_ICON = '<svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor"><path d="M19 9h-4V3H9v6H5l7 7 7-7zM5 18v2h14v-2H5z"/></svg>';

  function removeInjectedActions() {
    document.querySelectorAll('.ldcopy-actions').forEach((el) => el.remove());
  }

  async function injectButtons() {
    const { discourse, output, postExport, settings: settingsApi } = namespace;
    const settings = await settingsApi.getSettings();

    if (!settings.enablePostActions) {
      removeInjectedActions();
      return;
    }

    discourse.getPostElements().forEach((postEl) => {
      if (postEl.querySelector('.ldcopy-actions')) return;

      const actionsEl = postEl.querySelector('.post-controls, .actions');
      if (!actionsEl) return;

      const wrapper = document.createElement('div');
      wrapper.className = 'ldcopy-actions';

      const copyBtn = document.createElement('button');
      copyBtn.className = 'ldcopy-btn';
      copyBtn.title = '复制本楼原始 Markdown';
      copyBtn.innerHTML = `${COPY_ICON} <span>复制</span>`;
      copyBtn.addEventListener('click', async (event) => {
        event.preventDefault();
        event.stopPropagation();
        copyBtn.disabled = true;
        try {
          const latestSettings = await settingsApi.getSettings();
          const result = await postExport.buildPostMarkdown(postEl, latestSettings);
          await output.copyToClipboard(result.markdown);
          output.showToast('✅ 已复制到剪贴板');
        } catch (err) {
          output.showToast('❌ 失败: ' + err.message);
        } finally {
          copyBtn.disabled = false;
        }
      });

      const downloadBtn = document.createElement('button');
      downloadBtn.className = 'ldcopy-btn';
      downloadBtn.title = '下载本楼为 Markdown 文件';
      downloadBtn.innerHTML = `${DOWNLOAD_ICON} <span>下载</span>`;
      downloadBtn.addEventListener('click', async (event) => {
        event.preventDefault();
        event.stopPropagation();
        downloadBtn.disabled = true;
        try {
          const latestSettings = await settingsApi.getSettings();
          const result = await postExport.buildPostMarkdown(postEl, latestSettings);
          const title = discourse.getTopicTitle();
          const filename = output.sanitizeFilename(`${title}_#${result.meta.postNumber || 'post'}.md`);
          output.downloadFile(result.markdown, filename);
          output.showToast(`✅ 已下载 ${filename}`);
        } catch (err) {
          output.showToast('❌ 失败: ' + err.message);
        } finally {
          downloadBtn.disabled = false;
        }
      });

      wrapper.appendChild(copyBtn);
      wrapper.appendChild(downloadBtn);
      actionsEl.appendChild(wrapper);
    });
  }

  namespace.buttons = {
    injectButtons,
    removeInjectedActions,
  };
})();


/* ===== src/content/base64.js ===== */
/* Linux.do 工具箱 — Base64 选择工具模块 */
(() => {
  'use strict';

  const namespace = globalThis.LinuxDoToolkit = globalThis.LinuxDoToolkit || {};

  function decodeBase64Utf8(text) {
    const normalized = text.replace(/\s+/g, '');
    const binary = atob(normalized);
    const bytes = Uint8Array.from(binary, (char) => char.charCodeAt(0));

    try {
      return new TextDecoder('utf-8', { fatal: true }).decode(bytes);
    } catch {
      // 兼容非 UTF-8 或历史内容，尽量给出可读结果。
      return binary;
    }
  }

  async function injectBase64Button() {
    const { output, settings: settingsApi } = namespace;
    const settings = await settingsApi.getSettings();
    if (!settings.enableBase64Decode) {
      document.querySelectorAll('.ldcopy-base64-btn').forEach((el) => el.remove());
      return;
    }

    const quoteContainer = document.querySelector('.quote-button');
    if (!quoteContainer || quoteContainer.querySelector('.ldcopy-base64-btn')) return;

    const base64Btn = document.createElement('button');
    base64Btn.className = 'btn btn-flat ldcopy-base64-btn';
    base64Btn.title = 'Base64 解码并复制';
    base64Btn.innerHTML = '<svg viewBox="0 0 24 24" width="14" height="14" fill="currentColor" style="vertical-align: middle; margin-right: 2px;"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 15l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z"/></svg>base64';
    base64Btn.style.cssText = 'margin-right: 4px; padding: 4px 8px; font-size: 13px; order: -1; display: inline-flex; align-items: center;';

    base64Btn.addEventListener('click', async (event) => {
      event.preventDefault();
      event.stopPropagation();
      try {
        const selectedText = window.getSelection().toString().trim();
        if (!selectedText) {
          output.showToast('❌ 未选中文字');
          return;
        }
        await output.copyToClipboard(decodeBase64Utf8(selectedText));
        output.showToast('✅ Base64 解码已复制');
      } catch (err) {
        output.showToast('❌ Base64 解码失败: ' + err.message);
      }
    });

    quoteContainer.insertBefore(base64Btn, quoteContainer.firstChild);
  }

  namespace.base64 = {
    decodeBase64Utf8,
    injectBase64Button,
  };
})();


/* ===== src/content/messages.js ===== */
/* Linux.do 工具箱 — popup 消息通信模块 */
(() => {
  'use strict';

  const namespace = globalThis.LinuxDoToolkit = globalThis.LinuxDoToolkit || {};

  function registerMessageHandlers() {
    const { discourse, output, postExport, settings: settingsApi } = namespace;

    chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {
      if (msg.action === 'getInfo') {
        const postEls = discourse.getPostElements();
        sendResponse({
          title: discourse.getTopicTitle(),
          url: discourse.getTopicUrl(),
          postCount: postEls.length,
        });
        return true;
      }

      if (msg.action === 'refreshEnhancements') {
        namespace.app?.refreshEnhancements?.();
        sendResponse({ success: true });
        return true;
      }

      if (msg.action === 'copyTopic') {
        (async () => {
          try {
            const settings = await settingsApi.getSettings();
            const posts = await postExport.getAllPostsRaw(settings);
            const md = output.formatTopicMd(posts, discourse.getTopicTitle(), discourse.getTopicUrl(), settings);
            await output.copyToClipboard(md);
            sendResponse({ success: true });
            output.showToast('✅ 已复制整个主题');
          } catch (err) {
            sendResponse({ success: false, error: err.message });
            output.showToast('❌ 失败: ' + err.message);
          }
        })();
        return true;
      }

      if (msg.action === 'downloadTopic') {
        (async () => {
          try {
            const settings = await settingsApi.getSettings();
            const posts = await postExport.getAllPostsRaw(settings);
            const title = discourse.getTopicTitle();
            const md = output.formatTopicMd(posts, title, discourse.getTopicUrl(), settings);
            const filename = output.sanitizeFilename(`${title}.md`);
            output.downloadFile(md, filename);
            sendResponse({ success: true, filename });
            output.showToast(`✅ 已下载 ${filename}`);
          } catch (err) {
            sendResponse({ success: false, error: err.message });
            output.showToast('❌ 失败: ' + err.message);
          }
        })();
        return true;
      }

      return false;
    });
  }

  namespace.messages = {
    registerMessageHandlers,
  };
})();


/* ===== src/content/index.js ===== */
/* Linux.do 工具箱 — Content Script 入口 */
(() => {
  'use strict';

  const namespace = globalThis.LinuxDoToolkit = globalThis.LinuxDoToolkit || {};

  function refreshEnhancements() {
    namespace.buttons.injectButtons();
    namespace.base64.injectBase64Button();
  }

  function bindDynamicPageEvents() {
    document.addEventListener('selectionchange', () => {
      setTimeout(() => namespace.base64.injectBase64Button(), 100);
    });

    const observer = new MutationObserver(() => refreshEnhancements());
    observer.observe(document.querySelector('#main-outlet, #main, body') || document.body, {
      childList: true,
      subtree: true,
    });

    window.addEventListener('discourse-navigate-completed', refreshEnhancements);
    window.addEventListener('page:change', refreshEnhancements);
  }

  function init() {
    namespace.app = { refreshEnhancements };
    namespace.messages.registerMessageHandlers();
    refreshEnhancements();
    bindDynamicPageEvents();
    namespace.settings.onSettingsChanged(refreshEnhancements);
  }

  init();
})();
